'use client'

import { motion } from 'framer-motion'
import Link from 'next/link'
import { Zap, Menu, X } from 'lucide-react'
import { useState } from 'react'
import { Button } from '@/components/ui/Button'

export default function Header() {
  const [isMenuOpen, setIsMenuOpen] = useState(false)

  return (
    <header className="sticky top-0 z-50 backdrop-blur-md bg-white/90 border-b border-blue-200/40">
      <nav className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
        {/* Logo */}
        <Link href="/" className="flex items-center gap-2">
          <div className="p-2 rounded-lg bg-gradient-to-br from-blue-700 to-blue-900 shadow-md">
            <Zap className="w-5 h-5 text-white" />
          </div>
          <span className="text-lg font-bold text-blue-900 tracking-tight">SpendPilot</span>
        </Link>

        {/* Desktop Navigation */}
        <div className="hidden md:flex items-center gap-1">
          {[
            { href: '#features', label: 'Features' },
            { href: '#testimonials', label: 'Testimonials' },
            { href: '#pricing', label: 'Pricing' },
          ].map((item) => (
            <Link
              key={item.href}
              href={item.href}
              className="px-4 py-2 text-sm font-medium text-blue-700 hover:text-blue-900 rounded-lg hover:bg-blue-100/50 transition-all duration-200"
            >
              {item.label}
            </Link>
          ))}
        </div>

        {/* Right side - CTA Button */}
        <Link href="/audit" className="hidden sm:block">
          <Button size="sm" className="font-semibold bg-blue-700 hover:bg-blue-800 text-white shadow-md hover:shadow-lg transition-shadow">
            Start Audit
          </Button>
        </Link>

        {/* Mobile menu button */}
        <button
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          className="md:hidden p-2 rounded-lg hover:bg-blue-100 transition-colors"
        >
          {isMenuOpen ? (
            <X className="w-5 h-5 text-gray-600" />
          ) : (
            <Menu className="w-5 h-5 text-gray-600" />
          )}
        </button>
      </nav>

      {/* Mobile menu */}
      {isMenuOpen && (
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -10 }}
          className="md:hidden border-t border-gray-200/40 bg-white/95 backdrop-blur-md"
        >
          <div className="max-w-7xl mx-auto px-4 py-4 space-y-2">
            {[
              { href: '#features', label: 'Features' },
              { href: '#testimonials', label: 'Testimonials' },
              { href: '#pricing', label: 'Pricing' },
            ].map((item) => (
              <Link
                key={item.href}
                href={item.href}
                className="block px-4 py-2 text-sm font-medium text-gray-600 hover:text-gray-900 rounded-lg hover:bg-gray-100/50 transition-all duration-200"
                onClick={() => setIsMenuOpen(false)}
              >
                {item.label}
              </Link>
            ))}
            <Link href="/audit" className="block pt-2">
              <Button size="sm" className="w-full font-semibold bg-blue-600 hover:bg-blue-700 text-white shadow-md">
                Start Audit
              </Button>
            </Link>
          </div>
        </motion.div>
      )}
    </header>
  )
}
