'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { motion } from 'framer-motion'
import Header from '@/components/layout/Header'
import Footer from '@/components/layout/Footer'
import { AuditFlow } from '@/components/audit/AuditFlow'
import { Card } from '@/components/ui/Card'
import { Tool } from '@/types'

export default function AuditPage() {
  const router = useRouter()
  const [isLoading, setIsLoading] = useState(false)

  const handleAuditSubmit = async (tools: Tool[], teamSize: number, useCase: string) => {
    setIsLoading(true)
    try {
      const response = await fetch('/api/audit', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ tools, teamSize, useCase }),
      })

      if (!response.ok) throw new Error('Audit generation failed')

      const data = await response.json()
      router.push(`/results/${data.id}`)
    } catch (error) {
      console.error('Error:', error)
      alert('Failed to generate audit. Please try again.')
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <>
      <Header />
      <main className="min-h-screen bg-gray-950 py-20 px-4">
        <div className="max-w-3xl mx-auto">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="mb-12 text-center"
          >
            <h1 className="text-4xl md:text-5xl font-bold text-white mb-4">
              AI Tool Spend Audit
            </h1>
            <p className="text-xl text-gray-400">
              Answer a few questions and we'll analyze your spending patterns
            </p>
          </motion.div>

          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.2 }}
          >
            <Card className="p-8">
              <AuditFlow onSubmit={handleAuditSubmit} isLoading={isLoading} />
            </Card>
          </motion.div>
        </div>
      </main>
      <Footer />
    </>
  )
}
