'use client'

import { useState } from 'react'
import { motion } from 'framer-motion'
import { Button } from '@/components/ui/Button'
import { Input } from '@/components/ui/Input'
import { Select } from '@/components/ui/Select'
import { Card } from '@/components/ui/Card'
import { AI_TOOLS, TEAM_SIZE_OPTIONS, USE_CASES } from '@/constants/tools'
import { Tool } from '@/types'
import { Plus, X, ChevronRight, ChevronLeft } from 'lucide-react'

interface AuditFlowProps {
  onSubmit: (tools: Tool[], teamSize: number, useCase: string) => void
  isLoading?: boolean
}

export const AuditFlow: React.FC<AuditFlowProps> = ({ onSubmit, isLoading = false }) => {
  const [step, setStep] = useState(1)
  const [tools, setTools] = useState<Tool[]>([])
  const [selectedToolId, setSelectedToolId] = useState('')
  const [teamSize, setTeamSize] = useState('')
  const [useCase, setUseCase] = useState('')
  const [errors, setErrors] = useState<Record<string, string>>({})

  const handleAddTool = () => {
    if (!selectedToolId) {
      setErrors({ ...errors, tool: 'Please select a tool' })
      return
    }

    const toolData = AI_TOOLS.find((t) => t.id === selectedToolId)
    if (!toolData) return

    // Check if tool already added
    if (tools.find((t) => t.id === selectedToolId)) {
      setErrors({ ...errors, tool: 'This tool is already added' })
      return
    }

    const newTool: Tool = {
      id: selectedToolId,
      name: toolData.name,
      category: toolData.category,
      currentPlan: toolData.plans[0].name,
      monthlySpend: toolData.plans[0].monthlyPrice || 0,
      yearlySpend: (toolData.plans[0].yearlyPrice || 0),
    }

    setTools([...tools, newTool])
    setSelectedToolId('')
    setErrors({ ...errors, tool: '' })
  }

  const handleRemoveTool = (id: string) => {
    setTools(tools.filter((t) => t.id !== id))
  }

  const handleUpdateTool = (id: string, updates: Partial<Tool>) => {
    setTools(
      tools.map((t) => (t.id === id ? { ...t, ...updates } : t))
    )
  }

  const validateStep = () => {
    const newErrors: Record<string, string> = {}

    if (step === 1 && tools.length === 0) {
      newErrors.step1 = 'Add at least one AI tool'
    }

    if (step === 2) {
      if (!teamSize) newErrors.teamSize = 'Please select team size'
      if (!useCase) newErrors.useCase = 'Please select a use case'
    }

    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }

  const handleNext = () => {
    if (validateStep()) {
      setStep(step + 1)
    }
  }

  const handleSubmit = () => {
    if (validateStep()) {
      const teamSizeNum = parseInt(teamSize.split('-')[0])
      onSubmit(tools, teamSizeNum, useCase)
    }
  }

  return (
    <div className="space-y-8">
      {/* Progress indicator */}
      <div className="flex gap-2 justify-center mb-8">
        {[1, 2].map((s) => (
          <motion.div
            key={s}
            className={`h-1 rounded-full transition-all duration-300 ${
              step >= s ? 'bg-blue-500' : 'bg-gray-700'
            }`}
            initial={{ width: 0 }}
            animate={{ width: step >= s ? 96 : 96 }}
          />
        ))}
      </div>

      {/* Step 1: Tools Selection */}
      {step === 1 && (
        <motion.div
          initial={{ opacity: 0, x: 20 }}
          animate={{ opacity: 1, x: 0 }}
          exit={{ opacity: 0, x: -20 }}
          className="space-y-6"
        >
          <div>
            <h2 className="text-3xl font-bold text-white mb-2">Which AI tools does your team use?</h2>
            <p className="text-gray-400">Start by selecting the tools and their current plans</p>
          </div>

          {/* Tool selector */}
          <Card>
            <div className="space-y-4">
              <Select
                label="Select AI Tool"
                value={selectedToolId}
                onChange={(e) => {
                  setSelectedToolId(e.target.value)
                  setErrors({ ...errors, tool: '' })
                }}
                options={[
                  { value: '', label: 'Choose a tool...' },
                  ...AI_TOOLS.map((tool) => ({
                    value: tool.id,
                    label: tool.name,
                  })),
                ]}
              />
              {errors.tool && <p className="text-sm text-red-400">{errors.tool}</p>}
              <Button
                onClick={handleAddTool}
                variant="secondary"
                className="w-full gap-2"
                disabled={!selectedToolId}
              >
                <Plus size={20} />
                Add Tool
              </Button>
            </div>
          </Card>

          {/* Selected tools */}
          {tools.length > 0 && (
            <div className="space-y-4">
              <h3 className="text-lg font-semibold text-white">Your Tools ({tools.length})</h3>
              <div className="space-y-3">
                {tools.map((tool, i) => {
                  const toolConfig = AI_TOOLS.find((t) => t.id === tool.id)
                  return (
                    <motion.div
                      key={tool.id}
                      initial={{ opacity: 0, y: 20 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -20 }}
                    >
                      <Card className="p-4">
                        <div className="flex items-start justify-between gap-4">
                          <div className="flex-1">
                            <div className="flex items-center gap-2 mb-3">
                              <h4 className="font-semibold text-white">{tool.name}</h4>
                              <span className="text-xs bg-gray-800 text-gray-300 px-2 py-1 rounded">
                                {tool.category}
                              </span>
                            </div>
                            
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                              <Select
                                label="Plan"
                                value={tool.currentPlan}
                                onChange={(e) => {
                                  const plan = toolConfig?.plans.find((p) => p.name === e.target.value)
                                  if (plan) {
                                    handleUpdateTool(tool.id, {
                                      currentPlan: e.target.value,
                                      monthlySpend: plan.monthlyPrice || 0,
                                      yearlySpend: plan.yearlyPrice || 0,
                                    })
                                  }
                                }}
                                options={toolConfig?.plans.map((p) => ({
                                  value: p.name,
                                  label: p.name,
                                })) || []}
                              />
                              
                              <Input
                                label="Monthly Spend ($)"
                                type="number"
                                value={tool.monthlySpend}
                                onChange={(e) =>
                                  handleUpdateTool(tool.id, {
                                    monthlySpend: parseFloat(e.target.value) || 0,
                                  })
                                }
                              />
                            </div>
                          </div>

                          <button
                            onClick={() => handleRemoveTool(tool.id)}
                            className="p-2 hover:bg-red-500/10 rounded-lg transition-colors text-red-400"
                          >
                            <X size={20} />
                          </button>
                        </div>
                      </Card>
                    </motion.div>
                  )
                })}
              </div>
            </div>
          )}

          {errors.step1 && <p className="text-sm text-red-400">{errors.step1}</p>}
        </motion.div>
      )}

      {/* Step 2: Team & Use Case */}
      {step === 2 && (
        <motion.div
          initial={{ opacity: 0, x: 20 }}
          animate={{ opacity: 1, x: 0 }}
          exit={{ opacity: 0, x: -20 }}
          className="space-y-6"
        >
          <div>
            <h2 className="text-3xl font-bold text-white mb-2">Tell us about your team</h2>
            <p className="text-gray-400">This helps us provide better recommendations</p>
          </div>

          <Card className="space-y-6">
            <Select
              label="Team Size"
              value={teamSize}
              onChange={(e) => {
                setTeamSize(e.target.value)
                setErrors({ ...errors, teamSize: '' })
              }}
              options={TEAM_SIZE_OPTIONS}
              error={errors.teamSize}
            />

            <Select
              label="Primary Use Case"
              value={useCase}
              onChange={(e) => {
                setUseCase(e.target.value)
                setErrors({ ...errors, useCase: '' })
              }}
              options={USE_CASES.map((uc) => ({
                value: uc,
                label: uc,
              }))}
              error={errors.useCase}
            />
          </Card>

          {errors.step1 && <p className="text-sm text-red-400">{errors.step1}</p>}
        </motion.div>
      )}

      {/* Navigation buttons */}
      <div className="flex gap-4 justify-between pt-8 border-t border-gray-800">
        <Button
          variant="outline"
          onClick={() => step > 1 && setStep(step - 1)}
          disabled={step === 1}
          className="gap-2"
        >
          <ChevronLeft size={20} />
          Back
        </Button>

        <div className="flex gap-4">
          {step === 1 && (
            <Button
              onClick={handleNext}
              className="gap-2"
            >
              Next
              <ChevronRight size={20} />
            </Button>
          )}

          {step === 2 && (
            <>
              <Button
                onClick={() => setStep(step - 1)}
                variant="outline"
                className="gap-2"
              >
                <ChevronLeft size={20} />
                Back
              </Button>
              <Button
                onClick={handleSubmit}
                loading={isLoading}
                className="gap-2"
              >
                Generate Audit
                <ChevronRight size={20} />
              </Button>
            </>
          )}
        </div>
      </div>
    </div>
  )
}
